import{_ as e,c as r,o as a,a4 as t}from"./chunks/framework.HaEZziQ1.js";const u=JSON.parse('{"title":"Chrome插件开发入门","description":"","frontmatter":{},"headers":[],"relativePath":"Document/Chrome 插件开发/Chrome插件开发入门.md","filePath":"Document/Chrome 插件开发/Chrome插件开发入门.md","lastUpdated":1709668918000}'),p={name:"Document/Chrome 插件开发/Chrome插件开发入门.md"},o=t('<h1 id="chrome插件开发入门" tabindex="-1">Chrome插件开发入门 <a class="header-anchor" href="#chrome插件开发入门" aria-label="Permalink to &quot;Chrome插件开发入门&quot;">​</a></h1><p>Chrome插件开发文档：<a href="https://developer.chrome.com/extensions" target="_blank" rel="noreferrer">developer.chrome.com</a></p><h2 id="文章" tabindex="-1">文章 <a class="header-anchor" href="#文章" aria-label="Permalink to &quot;文章&quot;">​</a></h2><p><a href="https://juejin.cn/post/6951366925557432356" target="_blank" rel="noreferrer">开发chrome插件实现爬虫 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/6844903508966113287" target="_blank" rel="noreferrer">chrome插件 DIY - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/7035782439590952968" target="_blank" rel="noreferrer">从零深入Chrome插件开发 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/7124085369926074399" target="_blank" rel="noreferrer">🌕手把手从0撸一个 Chrome 插件，《特别关注-掘金》 功能 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/7114959554709815326" target="_blank" rel="noreferrer">字节跳动 chrome 插件开发指南 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/6970912734086955045" target="_blank" rel="noreferrer">飞书 chrome 插件开发指南 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/7035782439590952968" target="_blank" rel="noreferrer">从零深入Chrome插件开发 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/7122332008252080142" target="_blank" rel="noreferrer">【程序员的浪漫】七夕到了，还不快给你女朋友做一个专属chrome插件 - 掘金 (juejin.cn)</a></p><p><a href="https://juejin.cn/post/6844904119828742152" target="_blank" rel="noreferrer">30分钟开发一款抓取网站图片资源的浏览器插件 - 掘金 (juejin.cn)</a></p><p><a href="http://www.360doc.com/content/22/0913/16/11604731_1047745325.shtml" target="_blank" rel="noreferrer">Chrome插件开发教程之入门指南 (360doc.com)</a></p><p><a href="https://blog.csdn.net/CShadow7/article/details/123730422" target="_blank" rel="noreferrer">Chrome插件开发入门_谷歌插件开发_CShadow7的博客-CSDN博客</a></p><p><a href="http://www.manongjc.com/detail/51-uzjfsulporgmlpm.html" target="_blank" rel="noreferrer">10分钟教你开发自己的Chrome浏览器插件 - 码农教程 (manongjc.com)</a></p><p>视频课程：<a href="https://www.bilibili.com/video/av763262694/?vd_source=5f0c99b3deddffe219938763769b15ac" target="_blank" rel="noreferrer">chrome浏览器插件开发视频教程_哔哩哔哩_bilibili</a></p><hr><p>文章参考：<a href="https://juejin.cn/post/7167562121768042532" target="_blank" rel="noreferrer">Chrome 插件开发入门 - 掘金 (juejin.cn)</a></p><p>Chrome 的界面布局和插件式设计决定了其可能的扩展点和机制。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/f52ab9ecdab94925afa971af29eaa085~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h3 id="manifest-json-配置入口" tabindex="-1">Manifest.json:配置入口 <a class="header-anchor" href="#manifest-json-配置入口" aria-label="Permalink to &quot;Manifest.json:配置入口&quot;">​</a></h3><p>用以配置应用名、版本，以及所需的系统权限，最重要、不可缺少，必须置于根目录</p><ul><li><strong>manifest_version</strong>: 插件版本</li></ul><p>目前只支持上架和更新 v3 版本，v2 不再支持，必须在 2023 年前全部替换。且 V3 版的上架审核优先级更高，周期更短。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/ea2a4521cd5945e2bad90b1b9a7fdf2b~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><p>v3版本对 v2 版的组件和API进行了大幅度的优化和安全增强，最主要的变动如下图</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/94768f5f685b48ad99986ffaf792b937~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><ul><li><strong>Permission 权限</strong></li></ul><p>需要申请正确的权限才可以调用相应的API，如操作选项卡的 tabs 权限。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/afa9411b69f34e73a4da941dfcc45c64~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><p><strong>最小权限原则</strong>：尽量使用必要的权限，过多的、敏感权限将导致审核时间大大延长，甚至拒绝</p><p><img src="https://p9-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/59d2312c7d734cb392363b7972f3ea8f~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp?" alt="componets permission.png"></p><p>v3版本中Api Permission 和 Host Permission 分离，以更清晰的界定权限类别。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/0906b261e33e4a6995468964e0ee438f~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h3 id="service-worker-中央处理器" tabindex="-1">Service Worker: 中央处理器 <a class="header-anchor" href="#service-worker-中央处理器" aria-label="Permalink to &quot;Service Worker: 中央处理器&quot;">​</a></h3><p>本质上是浏览器在后台运行的脚本，它是完全独立于它正在处理或服务的网页。它们充当了 web 应用程序、浏览器和网络之间的代理服务器。service worker 赋予 Web 应用程序像原生应用程序一样工作的能力</p><ul><li><strong>无状态瞬时组件</strong>：在浏览器启动后初始化执行，便销毁</li><li><strong>事件驱动</strong>： 通过注册各类事件监听器，作为其他组件间的中央处理和通信单元</li><li><strong>权限最大：</strong> 可以调用除了 Dom 外的大部分API，完成其他组件不可用执行的功能</li></ul><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/a1ffcece9caf46fe968e31f76f43caa5~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp?" alt="img"></p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/b970805cbea84279802d72e9d7cd5dd3~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h3 id="popup-弹窗" tabindex="-1">Popup: 弹窗 <a class="header-anchor" href="#popup-弹窗" aria-label="Permalink to &quot;Popup: 弹窗&quot;">​</a></h3><p>点击browser<em>action或者page</em>action图标时打开的一个小窗口网页，焦点离开网页就立即关闭，一般用来做一些临时性的交互。</p><ul><li>大部分插件主要的交互区域、工作方式</li><li><strong>最大空间</strong>：800 x 600</li></ul><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/08d6919f04d5480aa00f713a4709ee0f~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h3 id="contentjs-内容脚本" tabindex="-1">ContentJs: 内容脚本 <a class="header-anchor" href="#contentjs-内容脚本" aria-label="Permalink to &quot;ContentJs: 内容脚本&quot;">​</a></h3><p>向当前主页面窗口中注入脚本的一种形式，最常见的比如：广告屏蔽、页面CSS定制。</p><ul><li>突破POP窗口大小的局限性，自由度更高</li><li>注意CSS样式污染，会导致部分宿主页面变形</li></ul><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/29e1d46f65ca433e89e2de3d378e04e6~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h2 id="插件diy-rename-tab" tabindex="-1">插件DIY - Rename Tab <a class="header-anchor" href="#插件diy-rename-tab" aria-label="Permalink to &quot;插件DIY - Rename Tab&quot;">​</a></h2><p><strong>背景</strong>:</p><p>部分网站的所有子页面的标题相同，当打开众多时，很难通过标题快速区分具体是哪个页面，影响并发多开基数。</p><p><strong>功能需求</strong>:</p><p>支持手动或自动修改当前页面Tab标题，增加Tab可辨识性、可搜索性。</p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/6c0a60552b2646579f6f8e3d62e9c476~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><p><img src="https://p3-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/1933994b05444c91b4a2cea6861f06e1~tplv-k3u1fbpfcp-zoom-in-crop-mark:4536:0:0:0.awebp" alt="img"></p><h3 id="链接" tabindex="-1">链接 <a class="header-anchor" href="#链接" aria-label="Permalink to &quot;链接&quot;">​</a></h3><ul><li><a href="https://link.juejin.cn?target=https%3A%2F%2Fgitee.com%2Fcoderkkx%2Fchrome-crx-demo" target="_blank" rel="noreferrer">Rename Tab</a></li></ul>',56),n=[o];function i(c,s,m,l,f,h){return a(),r("div",null,n)}const g=e(p,[["render",i]]);export{u as __pageData,g as default};
